
console.log("projects-create-init loaded");

"use strict";

$(document).ready(function () {

  // ===============================
  // FORM VALIDATION
  // ===============================
  $("#project-type").validate();
  $("#project-details").validate();
  $("#project-settings").validate();
  $("#project-budgets").validate();

  // ===============================
  // WIZARD INITIALIZATION
  // ===============================
  $("#project-create-steps").steps({
    headerTag: "div.step-title",
    bodyTag: "section.step-body",
    transitionEffect: "slideLeft",
    titleTemplate: "#title#",
    enableAllSteps: true,

    onStepChanging: function (event, currentIndex, newIndex) {
      if (newIndex < currentIndex) return true;

      var form = $(".body.current form");
      if (form.length === 1) {
        form.validate().settings.ignore = ":disabled,:hidden";
        return form.valid();
      }
      return true;
    },

    onFinishing: function () {
      var form = $(".body.current form");
      if (form.length === 1) {
        form.validate().settings.ignore = ":disabled";
        return form.valid();
      }
      return true;
    },

    onFinished: function () {
  const swal = Swal.mixin({
    customClass: {
      confirmButton: "btn btn-success m-1",
      cancelButton: "btn btn-danger m-1",
    },
    buttonsStyling: false,
  });

  swal.fire({
    title: "Created & Finished",
    text: "You want to create and finish this project?",
    icon: "warning",
    showCancelButton: true,
    confirmButtonText: "Yes, Create it!",
    cancelButtonText: "No, cancel!",
    reverseButtons: true,
  }).then((result) => {
    if (result.isConfirmed) {

      // 🔥 HARD FORCE SUBMIT (BYPASSES jQuery Steps)
      const form = document.getElementById("projectCreateForm");

      form.removeEventListener("submit", function () {});
      form.submit();
    }
  });
},
  });

  // ===============================
  // SELECT2
  // ===============================
  $("#projectClient, #tragetAssigned").select2({
    theme: "bootstrap-5",
    templateResult: userformat,
    templateSelection: userformat,
  });

  $("#billingType, #projectStatus, #projectTags, #tragetTags, [data-select2-teammates='teammates']").select2({
    theme: "bootstrap-5",
    templateResult: bgformat,
    templateSelection: bgformat,
  });

  $("#sendcontactsNotifications").select2({
    theme: "bootstrap-5",
    templateResult: iformat,
    templateSelection: iformat,
  });

});


// ===============================
// QUILL EDITORS (SAFE INIT)
// ===============================
$(document).ready(function () {

  if (document.getElementById("projectDescription")) {
    new Quill("#projectDescription", {
      placeholder: "Compose an epic...",
      theme: "snow",
    });
  }

  if (document.getElementById("targetDescription")) {
    new Quill("#targetDescription", {
      placeholder: "Compose an epic...",
      theme: "snow",
    });
  }

});


// ===============================
// FILE INPUT LABEL
// ===============================
$(document).ready(function () {
  $("#choose-file").change(function () {
    var fileName = this.files[0]?.name || "";
    $(this).prev("label").text(fileName);
  });
});
